      "id": "hope-waiver-respite-care",
      "name": "Respite Care/Caregiver Support (HOPE Waiver & Family Support 360)",
      "shortName": "HOPE Waiver Respite",
      "tagline": "Get paid respite care and support services so your loved one can stay home instead of entering a nursing facility",
